>>> schema = {
...     "type": "object",
...     "required": ["id", "name"],
...     "properties": {
...         "id": {
...             "type": "integer",
...             "format": "int64"
...         },
...         "name": {
...             "type": "string",
...             "example": "John Smith"
...         },
...         "tag": {
...             "type": "string"
...         }
...     }
... }
>>> example = example_from_schema(schema)
>>> assert example == {
...     "id": 1,
...     "name": "John Smith",
...     "tag": "string"
... }
```

